import json, sys

def load(path):
    with open(path) as f:
        raw = f.read().strip()
    return json.loads(f"[{raw.replace('}{', '},{')}]") if raw else []

baseline_issues = {(i["code"], i["selector"]) for i in load(sys.argv[1])}
current_issues  = {(i["code"], i["selector"]) for i in load(sys.argv[2])}

new_issues = current_issues - baseline_issues
if new_issues:
    print(f"FAIL: {len(new_issues)} new accessibility issue(s) not in baseline:")
    for code, selector in sorted(new_issues):
        print(f"  {code}  {selector}")
    sys.exit(1)
else:
    print(f"OK: no new issues ({len(current_issues)} known, {len(baseline_issues)} in baseline)")

{
  "suppressions": [
    {
      "rule": "color-contrast",
      "impact": "serious",
      "route": "/chat",
      "selector": ".user-message",
