UNSUPPRESSIBLE = {
    "aria-live-assertive-on-stream",   # custom rule: catches aria-live=assertive on #message-list
    "label",                           # missing form label on chat input
    "focus-trap",                      # keyboard trap inside input area
    "use-of-color",                    # color alone conveys AI vs user message
}

def is_suppressed(issue, suppressions):
    if issue["code"] in UNSUPPRESSIBLE:
        return False          # blocklist wins
    return any(
        s["rule"] == issue["code"] and s["selector"] == issue["selector"]
        for s in suppressions
    )

// tests/a11y/custom-axe-rules.js
const customRules = [
  {
    id: "genai-stream-polite",
    description: "Message list must use aria-live=polite, not assertive",
    tags: ["wcag2aa", "genai"],
    all: [],
    any: [],
    none: [
      {
        id: "genai-stream-assertive-check",
        evaluate(node) {
          // Returns true (violation) if aria-live is assertive on #message-list
          const live = node.getAttribute("aria-live");
          return live === "assertive";
        },
        metadata: {
          impact: "critical",
          messages: {
            pass: "aria-live is polite on message list",
            fail: "aria-live is assertive — will interrupt screen reader users during streaming",
          },
        },
      },
    ],
    selector: "#message-list, [role='log']",
    metadata: {
      url: "https://www.w3.org/WAI/WCAG21/Understanding/status-messages",
      description:
        "Assertive live regions interrupt the user. Chat streams must use polite.",
      help: "Set aria-live=polite on the AI message container",
      helpUrl: "#",
    },
  },
  {
    id: "genai-thinking-has-status",
    description: "Thinking indicator must use role=status so it does not steal focus",
    tags: ["wcag2aa", "genai"],
    all: [],
    any: [
      {
        id: "genai-thinking-role-check",
        evaluate(node) {
          return node.getAttribute("role") === "status";
        },
        metadata: {
          impact: "serious",
          messages: {
            pass: "Thinking indicator has role=status",
            fail: "Thinking indicator lacks role=status — screen readers may not announce it",
          },
        },
      },
    ],
    none: [],
    selector: "#thinking-indicator, [aria-label*='Thinking'], [aria-label*='thinking']",
    metadata: {
      url: "https://www.w3.org/WAI/WCAG21/Understanding/status-messages",
      description: "Thinking indicator must be in the accessibility tree with role=status.",
      help: "Add role=status to the thinking indicator element",
      helpUrl: "#",
    },
  },
];

module.exports = customRules;

# Register custom rules in the Playwright test
from axe_playwright_python.sync_playwright import Axe
import json, pathlib

AXE_OPTIONS = {
    "runOnly": {"type": "tag", "values": ["wcag2a", "wcag2aa", "wcag21aa", "genai"]},
}

def run_with_custom_rules(page):
    rules_js = pathlib.Path("tests/a11y/custom-axe-rules.js").read_text()
    # Register custom rules before running axe
    page.evaluate(f"""
        const customRules = {rules_js.replace("module.exports = customRules;", "customRules")};
        customRules.forEach(r => axe.configure({{ rules: [r] }}));
    """)
    axe = Axe()
    return axe.run(page, options=AXE_OPTIONS)

